parameters.jsCode:
const items = $input.all();
const results = [];

for (const item of items) {
  const email = item.json;
  const fromRaw = email.From || '';
  const emailMatch = fromRaw.match(/<([^>]+)>/);
  const senderEmail = emailMatch ? emailMatch[1] : fromRaw;
  const subject = email.Subject || '';
  const text = email.snippet || '';

  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://argos-api:8000/analyze_email',
      body: {
        sender: fromRaw,
        subject: subject,
        body: text
      },
      json: true,
      timeout: 60000
    });

    if (response.status === 'ignored') {
      console.log(`Skipping email: ${response.reason}`);
      continue;
    }

    const importanza = response.priority || 'medium';
    if (importanza.includes('low') || importanza.includes('bassa')) continue;

    const riassunto = response.summary || '';
    const draftPlain = response.draft || '';

    const draftHtml = '<div style="font-family: Arial, sans-serif; font-size: 14px; line-height: 1.6;">' +
      draftPlain.split('\n\n').map(p => '<p style="margin: 0 0 12px 0;">' + p.replace(/\n/g, '<br>') + '</p>').join('') +
      '</div>';

    results.push({ json: { 
      senderEmail, 
      subject, 
      messageId: email.id || '', 
      threadId: email.threadId || '', 
      importanza, 
      riassunto, 
      draft: draftPlain, 
      draftHtml, 
      fromRaw 
    }});
  } catch(e) {
    console.error("ARGOS API Execution Error:", e);
  }
}

return results;

